#include <stdio.h>
#include <sys/stat.h>

int main() {
    const char *filename = "myfile.txt";

    // Method 1: Using symbolic notation
    // chmod(filename, S_IRUSR | S_IWUSR | S_IRGRP | S_IROTH);
    // Equivalent to: chmod 644 (rw-r--r--)

    // Method 2: Using numeric (octal) notation
    // Owner: rwx = 4+2+1 = 7
    // Group: r-x = 4+0+1 = 5
    // Others: r-- = 4+0+0 = 4
    // mode = 0754

    mode_t mode = 0754;

    if (chmod(filename, mode) == 0) {
        printf("Permissions set to 0754 (rwxr-xr--)\n");
    }

    // Check current permissions
    struct stat fileStat;
    stat(filename, &fileStat);

    printf("File permissions: %o\n", fileStat.st_mode & 0777);

    // Check specific permissions
    if (fileStat.st_mode & S_IRUSR) printf("Owner can read\n");
    if (fileStat.st_mode & S_IWUSR) printf("Owner can write\n");
    if (fileStat.st_mode & S_IXUSR) printf("Owner can execute\n");

    return 0;
}
